const globalResult = $input.first();
let globalAnalysis = {};
try {
  let content = '';
  if (globalResult.json.message && globalResult.json.message.content) {
    content = globalResult.json.message.content;
  } else if (globalResult.json.text) {
    content = globalResult.json.text;
  } else if (globalResult.json.content) {
    content = globalResult.json.content;
  }
  content = content.replace(/```json\n?|```/g, '').trim();
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    globalAnalysis = JSON.parse(match[0]);
  }
} catch (e) {
  globalAnalysis = { error: 'Failed to parse global: ' + e.message };
}
const enrichData = $('Enrich + Extrair Plano').first().json;
return [{ json: { ...enrichData, global_analysis: globalAnalysis } }];

